formula:
period = 20;
mult_bb = 2.0;
mult_kc = 1.5;

// 1. 볼린저 밴드 상단/하단
bb_up = BBandsUp(period, mult_bb);
bb_low = BBandsDown(period, mult_bb);

// 2. 켈트너 채널 상단/하단 (ATR 기반)
kc_up = eavg(C, period) + ATR(period) * mult_kc;
kc_low = eavg(C, period) - ATR(period) * mult_kc;

// 3. 스퀴즈 조건: 볼린저 밴드가 켈트너 채널 안으로 압축됨
is_sq = (bb_up < kc_up) && (bb_low > kc_low);

// 4. 최종 신호: 어제까지 스퀴즈였고, 오늘 스퀴즈를 상향 탈출하며 종가가 볼밴 상단 돌파
is_sq(1) && (bb_up > kc_up) && CrossUp(C, bb_up)
